<div class="panel"><form method="post" action="<?= base_url('/admin/settings') ?>"><input type="hidden" name="_csrf" value="<?= htmlspecialchars(csrf_token()) ?>"><div class="form-grid admin-form-grid"><?php foreach ($keys as $key): ?><label class="<?= in_array($key, ['hero_subtitle', 'address', 'seo_description', 'announcement_bar', 'footer_note'], true) ? 'full' : '' ?>"><span><?= htmlspecialchars($key) ?></span><?php if (in_array($key, ['hero_subtitle', 'address', 'seo_description', 'announcement_bar', 'footer_note'], true)): ?><textarea name="<?= htmlspecialchars($key) ?>" rows="4"><?= htmlspecialchars(setting($key, '')) ?></textarea><?php else: ?><input type="text" name="<?= htmlspecialchars($key) ?>" value="<?= htmlspecialchars(setting($key, '')) ?>"><?php endif; ?></label><?php endforeach; ?></div><button class="btn btn-primary" type="submit">Salvar settings</button></form></div>
